INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00097', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '內政部警政署於111年9月訂有「組合警力執行攔檢、盤查、逮捕、帶離等執勤安全觀念及執行 要領」，俾強化警察執勤之安全作為及觀念，下列有關該要領之敘述何者正確？', '["盤查汽車，應避免站於危險區域，盤查者負責盤查駕駛人，應站立於車體B柱旁，專注駕駛人 及車內狀況，並要求駕駛人熄火", "盤查機車時，盤查者站於機車左方、右方或車前進行盤查，並要求駕駛人熄火", "盤查行人時，盤查者、警戒者站立位置，應呈現前後之直線隊形，以利靈活運用", "車輛攔檢時，警車停放在受檢車輛前方，並在車內可觀察受檢車輛全貌之距離為適當距離"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00098', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依警察機關設置及巡簽巡邏箱實施要點之規定，下列有關之敘述，何者錯誤？', '["設置巡邏箱位置，應注意適當性及隱密性", "員警巡簽巡邏箱時，應於巡邏箱設置處周遭適當範圍，實施重點守望勤務5分鐘至10分鐘", "因應民眾需求及為民服務需要，可設置臨時性巡邏箱；並應於設置原因消滅後撤除", "應考量員警巡邏區（線）路程遠近及「巡守合一」勤務等時間因素，設置適量之巡邏箱供員警 巡簽"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00099', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依警察勤務條例之規定，下列有關規範警察分局可作為之敘述，何者正確？', '["警察分局於必要時，得設警衛派出所，在特定地區執行守護任務", "警察分局得指派人員編組機動隊，運用組合警力，在指定地區執行巡邏、路檢、臨檢等勤務", "警察分局基於事實需要，須將個別勤務與共同勤務分別實施時，得以分局為單位，指派員警專 責執行勤區查察", "警察分局應依勤務基準表，就治安狀況及所掌握之警力，按日排定勤務分配表執行之，並陳報 上級備查；變更時亦同"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00100', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依巡邏勤務手冊之規定，巡邏勤務由分駐（派出）所、分局與警察局負責規劃，以構成所、分局、 局三層巡邏網，下列有關敘述何者正確？', '["巡邏勤務實施方式，應運用組合警力編成機動警網執行", "第一層巡邏網由警察局負責規劃，實施面式巡邏", "第二層巡邏網由警察分局負責規劃，實施點線巡邏", "第三層巡邏網由警察分駐（派出）所負責規劃，實施面式巡邏"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00101', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '地方警察機關預算標準，由內政部報請行政院核定施行，地方警察機關經費不足時，得陳請補助 之程序，下列敘述何者正確？', '["桃園市政府警察局，報由內政部警政署轉請內政部核定", "新竹市警察局，報由內政部轉請行政院核定", "臺南市政府警察局，報由內政部警政署轉請內政部核定", "高雄市政府警察局，報由內政部轉請行政院核定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00102', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '警察機關應依失蹤人之直系血親尊親屬、法定代理人、監護人、配偶、直系血親卑親屬及民法第 1123條家長、家屬或親屬之報案實施查尋。警察機關得依特定單位、人員之失踪人口報案實施查 尋之特殊情形，下列敘述何者錯誤？', '["在臺無親屬者，依相關權責單位人員或戶籍地之村（里）、鄰長之報案辦理", "緊急案件（如山難）依其同行人員之報案辦理；事後應與其家長、家屬或親屬聯繫確認", "社政機關或其委託公、私立社福安置機構所安置之保護個案，依該管機關（構）之報案辦理", "家屬委由公、私立社福安置機構照顧之個案，依家屬或安置機構之報案辦理"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00103', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '依據警察勤務條例規定，有關勤前教育的敘述，下列何者正確？', '["基層勤前教育以警察分局為實施單位", "聯合勤前教育以警察局為實施單位", "專案勤前教育由分駐所、派出所平日實施", "勤前教育之實施，由警察機關視所轄勤務機構實際情形，規定其實施方式、時間及次數"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00104', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '下列何者為英國皮爾爵士（SirRobertPeel）於1829年成立現代警察之初所立下的九個原則（Sir', '["警察的基本任務是預防犯罪的發生", "警 察執勤能力繫於政府對警察活動的認同", "警民一體", "警察效率以破案能力為標準"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00105', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '根據內政部警政署組織法第2條明定，下列何者屬於警政署掌理的全國性警察業務？', '["各國駐華使領館及代表機構、官員之安全維護", "當舖業及保全業管理之規劃、督導", "社會保防、戶口查察與社會治安調查之協調、規劃及督導", "交通安全維護、交通工程秩序整理、交通事故及協助交通安全宣導之規劃、督導"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00106', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-9d260bf1', 'sub-police-8b7f1efc-03', NULL, 'single_choice', '有關治安顧慮人口之查訪，下列敘述何者正確？', '["治安顧慮人口之查訪期間，以緩刑、刑執行完畢或假釋出獄後3年內為限", "治安顧慮人口查訪作業，由戶籍地警察局辦理規劃、審核、列管及建檔", "警察發現查訪對象有違法之虞時，應勸告其到勤務處所，接受調查詢問", "刑責區員警應就列管查訪對象，每3個月主動與警勤區員警交換動態情資1次以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:12+00:00", "source_pdf_sha1": "18e3b6a2eba1", "answer_pdf_sha1": "918744a5530e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1006", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察學與警察勤務", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
